data_catalog: null  // ⚠️ no inventory`},P3={tag:"02 — Modeling",title:"Medallion Architecture",subtitle:"Separation of responsibilities in distinct layers, ensuring each zone has a clear and auditable quality contract, physically separating the Data Lake (Storage) from the Data Warehouse (Analytics).",raw_name:"Raw",raw_sub:"Raw ingestion",raw_badge:"Immutable",raw_items:["Faithful copy of source","No transformations","Partitioned by date","Parquet/Delta format"],bronze_name:"Bronze",bronze_sub:"Conformance",bronze_badge:"Validated",bronze_items:["Consistent typing","Basic deduplication","Metadata enrichment","Schema validation"],silver_name:"Silver",silver_sub:"Conformance & Enrichment",silver_badge:"Enriched",silver_items:["Cross-domain joins","Business rules applied","Quality validated","SCD Type 2 applied"],gold_name:"Gold",gold_sub:"Analytical consumption",gold_badge:"Published",gold_items:["Pre-aggregated metrics","Dimensional model","Certified KPIs","Exposed via API/BI"],maturity:"Data maturity",raw_label:"Raw",gold_label:"Certified",diagram_lake:"Data Lake (Object Storage)",diagram_dw:"Data Warehouse (Serving)",diagram_raw_desc:"Raw (Original/Immutable)",diagram_bronze_desc:"Bronze (Validated)",diagram_silver_desc:"Silver (Single Source of Truth)",diagram_gold_desc:"Gold (Star Schema)",diagram_consumption:"Consumption/Analytics"},D3={title:"Dimensional Modeling: Star Schema vs. Snowflake",subtitle:"Why does the Gold layer use Star Schema (Denormalized) modeling?",perf_title:"1. Optimized Performance",perf_desc:"Drastically minimizes complex JOINs in analytical queries. Data is pre-consolidated into directly connected fact and dimension tables.",usability_title:"2. Usability & Self-service",usability_desc:"Intuitive structure for analysts and business users. Easy to drag and drop fields in visualization tools (Power BI/Superset).",maint_title:"3. KPI Maintainability",maint_desc:"Facilitates the creation of consistent, consolidated DAX/SQL measures. Single, centralized business aggregation rules on the right dimensions.",diag_sales_fact:"FACT_SALES",diag_prod_dim:"DIM_PRODUCT",diag_date_dim:"DIM_DATE",diag_cust_dim:"DIM_CUSTOMER"},O3={tag:"03 — Decision",title:"Microsoft Fabric vs. Open Source",subtitle:"Weighted comparative analysis. The final recommendation considers XPTO's context: lean team, existing M365 ecosystem, and high delivery urgency.",th_criteria:"Criterion",th_weight:"Weight",th_fabric:"Microsoft Fabric",th_opensource:"Open Source",weight_high:"High",weight_med:"Medium",weight_low:"Low",rec_title:"Recommendation: Microsoft Fabric",rec_desc:"Given the presence of the M365 ecosystem, the priority in governance, and the business-required time-to-value, Microsoft Fabric offers the fastest and safest route. OneLake architecture eliminates storage duplication, and Purview resolves compliance natively.",btn_explore_fabric:"Explore Fabric",btn_explore_os:"Explore Open Source",c_gov:"Governance & Compliance",c_pbi:"Power BI Integration",c_tco:"Operational Cost (TCO)",c_time:"Time-to-Value",c_scale:"Scalability",c_maint:"Infrastructure Maintenance",c_skills:"Required Skills",c_m365:"M365 Ecosystem",s_gov_fab:"Native Purview",s_gov_os:"Manual Ranger/Atlas",s_pbi_fab:"Native Direct Lake",s_pbi_os:"Via JDBC, limited",s_tco_fab:"Unified license",s_tco_os:"Own infra / No license fee",s_time_fab:"< 2 weeks",s_time_os:"4–8 weeks",s_scale_fab:"Elastic capacity",s_scale_os:"Manual scaling",s_maint_fab:"Fully managed",s_maint_os:"Self-managed (Self-hosted)",s_skills_fab:"Fast curve (Azure)",s_skills_os:"Common OSS skills",s_m365_fab:"Native integration",s_m365_os:"Not integrated"},R3={tag_rec:"Recommended Path",tag_m365:"Microsoft 365 Ecosystem",title:"Microsoft Fabric Architecture",subtitle:"Unified analytical platform built on OneLake. A single SaaS license, zero storage silos, native governance, and full integration with XPTO's M365 ecosystem.",comp_title:"Architecture Components",comp_onelake_title:"Microsoft OneLake",comp_onelake_sub:"Unified Storage (SaaS)",comp_onelake_desc:"Centralized storage for all organizational data. Eliminates storage silos and allows multi-workload access to the same data without copy.",comp_purview_title:"Microsoft Purview",comp_purview_sub:"Governance & Catalog",comp_purview_desc:"Automatic data catalog, end-to-end data lineage, sensitive data classification, and policy-based access control. Native compliance.",comp_pbi_title:"Power BI Embedded",comp_pbi_sub:"Visualization & Reporting",comp_pbi_desc:"Interactive reports with Direct Lake mode (queries straight on Analysis Services RAM on OneLake) without data replication and with sub-second response.",comp_df_title:"Data Factory (Fabric)",comp_df_sub:"Orchestration & ETL",comp_df_desc:"Low-code orchestration pipelines with native connectors for XPTO's 50+ sources. Real-time CDC (Change Data Capture) support.",comp_synapse_title:"Synapse Analytics",comp_synapse_sub:"Scale Processing",comp_synapse_desc:"Distributed processing engine for complex transformations in Bronze/Silver layers. Supports Spark, T-SQL, and Python.",comp_sec_title:"Managed VNet & Security",comp_sec_sub:"Network Security",comp_sec_desc:"Managed network isolation for workloads. Private endpoints and dedicated IPs ensure data travels in encrypted private channels.",flow_title:"Flow Diagram (Microsoft Fabric)",flow_sources:"XPTO Sources",flow_fabric:"Microsoft Fabric (OneLake)",flow_shortcuts:"Shortcuts (No Copy)",flow_lakehouse:"Lakehouse (Bronze/Silver)",flow_warehouse:"Warehouse (Gold)",flow_governance:"Governance",flow_purview:"Purview: Catalog & RLS",flow_powerbi:"Power BI: Direct Lake",sec_gov_title:"Security & Governance (RLS in Gold)",sec_gov_desc:"With Microsoft Fabric, Row-Level Security (RLS) is configured centrally in the SQL Endpoint/Warehouse. A single security policy restricts data for Power BI reports and direct T-SQL queries, ensuring compliance without logic replication.",sec_gov_code_title:`-- RLS Example in Fabric Warehouse:
